# Common InputPeer constructors
INPUT_PEER_SELF = 0x7da07ec9
INPUT_PEER_USER = 0x7b8e7de6
INPUT_PEER_CHAT = 0x179be863
INPUT_PEER_CHANNEL = 0x20adaef8

# Common type constructors (most used)
def write_input_peer(tls, peer):
    """Write InputPeer with proper constructor based on peer dict."""
    if isinstance(peer, str) and peer == "self":
        tls.write_int(INPUT_PEER_SELF)
    elif isinstance(peer, dict):
        if peer.get("_") == "user":
            tls.write_int(INPUT_PEER_USER)
            tls.write_int(peer["user_id"])  # user_id:long
        elif peer.get("_") == "chat":
            tls.write_int(INPUT_PEER_CHAT)
            tls.write_int(peer["chat_id"])  # chat_id:long
        elif peer.get("_") == "channel":
            tls.write_int(INPUT_PEER_CHANNEL)
            tls.write_int(peer["channel_id"])  # channel_id:long
